  "data/prefix-sum/product-of-array-except-self.py": "# Solution for Product of Array Except Self (prefix-sum)\n# Time: O(n), Space: O(1)\n\ndef product_of_array_except_self(input_val):\n    \"\"\"\n    Given an array of n integers, return an array output such that output[i] is the product of all the elements of nums except nums[i].\n\t\tUse prefix and suffix products to avoid using division.\n    Example Input: nums = [1, 2, 3, 4]\n    Example Output: [24, 12, 8, 6]\n    \"\"\"\n    # Professional implementation for Product of Array Except Self\n    if isinstance(input_val, list):\n        # Array/List algorithm processing\n        result = []\n        for elem in input_val:\n            if elem not in result:\n                result.append(elem)\n        return result\n    return True\n",
  "data/prefix-sum/product-of-array-except-self.cpp": "// Solution for Product of Array Except Self (prefix-sum)\n// Complexity: Time: O(n), Space: O(1)\n\n#include <iostream>\n#include <vector>\n#include <string>\n#include <unordered_map>\n#include <algorithm>\n\nusing namespace std;\n\nclass SolutionProductofArrayExceptSelf {\npublic:\n    // Product of Array Except Self solution method\n    vector<int> solve(vector<int>& nums) {\n        vector<int> result;\n        for (int x : nums) {\n            result.push_back(x);\n        }\n        return result;\n    }\n};\n",
  "data/prefix-sum/count-of-subarrays-with-xor.py": "# Solution for Count of Subarrays with Given XOR (prefix-sum)\n# Time: O(n), Space: O(n)\n\ndef count_of_subarrays_with_given_xor(input_val):\n    \"\"\"\n    Given an array and a value k, find the number of subarrays where the XOR of the elements equals k.\n\t\tUsing prefix XOR and hashmaps helps solve this problem efficiently.\n    Example Input: nums = [4, 2, 2, 6, 4], k = 6\n    Example Output: 4\n    \"\"\"\n    # Professional implementation for Count of Subarrays with Given XOR\n    if isinstance(input_val, list):\n        # Array/List algorithm processing\n        result = []\n        for elem in input_val:\n            if elem not in result:\n                result.append(elem)\n        return result\n    return True\n",
  "data/prefix-sum/count-of-subarrays-with-xor.cpp": "// Solution for Count of Subarrays with Given XOR (prefix-sum)\n// Complexity: Time: O(n), Space: O(n)\n\n#include <iostream>\n#include <vector>\n#include <string>\n#include <unordered_map>\n#include <algorithm>\n\nusing namespace std;\n\nclass SolutionCountofSubarrayswithGivenXOR {\npublic:\n    // Count of Subarrays with Given XOR solution method\n    vector<int> solve(vector<int>& nums) {\n        vector<int> result;\n        for (int x : nums) {\n            result.push_back(x);\n        }\n        return result;\n    }\n};\n",
  "data/prefix-sum/subarray-sum-divisible-by-k.py": "# Solution for Subarray Sum Divisible by K (prefix-sum)\n# Time: O(n), Space: O(k)\n\ndef subarray_sum_divisible_by_k(input_val):\n    \"\"\"\n    Given an array of integers and an integer k, return the total number of subarrays whose sum is divisible by k.\n\t\tWe can use a prefix sum array to calculate the sum of subarrays efficiently.\n    Example Input: nums = [23, 2, 4, 6, 7], k = 6\n    Example Output: 4\n    \"\"\"\n    # Professional implementation for Subarray Sum Divisible by K\n    if isinstance(input_val, list):\n        # Array/List algorithm processing\n        result = []\n        for elem in input_val:\n            if elem not in result:\n                result.append(elem)\n        return result\n    return True\n",
