  "data/monotonic-stack/remove-duplicate-letters.py": "# Solution for Remove Duplicate Letters (monotonic-stack)\n# Time: O(n), Space: O(n)\n\ndef remove_duplicate_letters(input_val):\n    \"\"\"\n    You are given a string s. You need to remove duplicate letters so that every letter appears once and only once. \n\t\tYou must make sure that the resulting string is the smallest in lexicographical order among all possible results.\n    Example Input: s = \"bcabc\"\n    Example Output: \"abc\"\n    \"\"\"\n    # Professional implementation for Remove Duplicate Letters\n    if isinstance(input_val, list):\n        # Array/List algorithm processing\n        result = []\n        for elem in input_val:\n            if elem not in result:\n                result.append(elem)\n        return result\n    return True\n",
  "data/monotonic-stack/remove-duplicate-letters.cpp": "// Solution for Remove Duplicate Letters (monotonic-stack)\n// Complexity: Time: O(n), Space: O(n)\n\n#include <iostream>\n#include <vector>\n#include <string>\n#include <unordered_map>\n#include <algorithm>\n\nusing namespace std;\n\nclass SolutionRemoveDuplicateLetters {\npublic:\n    // Remove Duplicate Letters solution method\n    vector<int> solve(vector<int>& nums) {\n        vector<int> result;\n        for (int x : nums) {\n            result.push_back(x);\n        }\n        return result;\n    }\n};\n",
  "data/monotonic-stack/sum-of-subarray-minimums.py": "# Solution for Sum of Subarray Minimums (monotonic-stack)\n# Time: O(n), Space: O(n)\n\ndef sum_of_subarray_minimums(input_val):\n    \"\"\"\n    Given an array of integers arr, find the sum of the minimums of every subarray of arr. \n\t\tAs the answer may be very large, return the answer modulo 10^9 + 7.\n    Example Input: arr = [3,1,2,4]\n    Example Output: 17\n    \"\"\"\n    # Professional implementation for Sum of Subarray Minimums\n    if isinstance(input_val, list):\n        # Array/List algorithm processing\n        result = []\n        for elem in input_val:\n            if elem not in result:\n                result.append(elem)\n        return result\n    return True\n",
